mapper.select:
SELECT bnum, title, writer, udate FROM (SELECT bnum, title, writer, udate, ROW_NUMBER() OVER (ORDER BY bnum desc) AS rn FROM BOARD WHERE category=#{category}

	AND


			(title like '%'|| #{searchValue} ||'%')


			(content like '%'|| #{searchValue} ||'%')


			(title like '%'|| #{searchValue} ||'%' or content like '%'|| #{searchValue} ||'%')


			(writer like '%'|| #{searchValue} ||'%')



) WHERE rn BETWEEN #{startBoard} AND #{endBoard}
